from flask import Flask, request, jsonify
from hashlib import sha256
import secrets

app = Flask(__name__)

auth_codes = {}

@app.route('/authorize', methods=['POST'])
def authorize():
    user_id = request.json.get('user_id')
    code = secrets.token_urlsafe(16)
    auth_codes[code] = user_id
    return jsonify({'code': code}), 200

@app.route('/token', methods=['POST'])
def token():
    code = request.json.get('code')
    if code in auth_codes:
        user_id = auth_codes[code]
        access_token = sha256((user_id + secrets.token_urlsafe(16)).encode()).hexdigest()
        return jsonify({'access_token': access_token, 'user_id': user_id}), 200
    return jsonify({'error': 'Invalid authorization code'}), 400

@app.route('/validate', methods=['GET'])
def validate():
    code = request.args.get('code')
    if code in auth_codes:
        return jsonify({'valid': True, 'user_id': auth_codes[code]}), 200
    return jsonify({'valid': False}), 404

if __name__ == '__main__':
    app.run(debug=True)